/bin/bash -lc "./probe.sh 2>&1 | cat;
echo '---';
D7_SITE=\""'${D7_SITE:?set D7_SITE}"
cd "$D7_SITE"
url=$(ddev describe -j | jq -r '"'.raw.primary_url')
echo \"URL: "'$url"
echo '"'--- menu item (user 1) ---'
ddev drush php-eval '
  global "'$user; $user = user_load(1);
  menu_rebuild();
  $item = menu_get_item("api/healthstats");
  echo "access_callback: " . var_export($item["access_callback"], TRUE) . "'"\\n\";
  echo \"access_arguments: \" . var_export("'$item["access_arguments"], TRUE) . "'"\\n\";
  echo \"page_callback: \" . var_export("'$item["page_callback"], TRUE) . "'"\\n\";
  echo \"delivery_callback: \" . var_export("'$item["delivery_callback"], TRUE) . "'"\\n\";
  echo \"access for user1: \" . ("'$item["access"] ? "true" : "false") . "'"\\n\";
'
echo '--- access for anonymous (user 0) ---'
ddev drush php-eval '
  "'$anon = user_load(0);
  echo "uid0 roles: " . var_export($anon->roles, TRUE) . "'"\\n\";
  echo \"can view healthstats? \" . var_export(user_access(\"view healthstats\", "'$anon), TRUE) . "'"\\n\";
'
echo '--- verbose anon curl ---'
curl -sk -v \""'$url/api/healthstats" 2>&1 | head -80'

